import { useState } from "react";

const transactions = [
  { icon: "🛒", name: "Amazon", date: "Today", amount: "-€24.99", positive: false },
  { icon: "⬇️", name: "Top Up", date: "Yesterday", amount: "+€200.00", positive: true },
  { icon: "☕", name: "Starbucks", date: "Jun 1", amount: "-€5.40", positive: false },
];

export default function JetonCard() {
  const [from, setFrom] = useState("EUR");
  const [to, setTo] = useState("GBP");
  const [amount, setAmount] = useState("10");

  const rates = { EUR: 1, GBP: 0.832, USD: 1.08, INR: 89.5 };
  const flags = { EUR: "🇪🇺", GBP: "🇬🇧", USD: "🇺🇸", INR: "🇮🇳" };
  const currencies = ["EUR", "GBP", "USD", "INR"];
  const symbols = { EUR: "€", GBP: "£", USD: "$", INR: "₹" };

  const converted =
    amount && !isNaN(amount)
      ? ((parseFloat(amount) / rates[from]) * rates[to]).toFixed(2)
      : "0.00";

  return (
    <div
      className="min-h-screen flex items-center justify-center p-6 relative overflow-hidden"
      style={{ background: "linear-gradient(135deg, #c0392b 0%, #e74c3c 45%, #ff6b5b 100%)" }}
    >
      {/* Decorative blobs */}
      <div className="absolute top-10 right-10 w-64 h-64 rounded-full"
        style={{ background: "rgba(255,255,255,0.07)" }} />
      <div className="absolute bottom-10 left-10 w-48 h-48 rounded-full"
        style={{ background: "rgba(255,255,255,0.05)" }} />

      <div className="relative z-10 w-full max-w-sm flex flex-col gap-5">

        {/* Header */}
        <div className="flex justify-between items-center px-1">
          <span className="text-white text-2xl font-semibold tracking-tight">Jeton</span>
          <span
            className="text-white/70 text-sm border border-white/30 rounded-full px-3 py-1"
            style={{ background: "rgba(255,255,255,0.12)" }}
          >
            Wallet
          </span>
        </div>

        {/* Balance Card */}
        <div
          className="rounded-3xl p-6"
          style={{
            background: "rgba(255,255,255,0.15)",
            backdropFilter: "blur(20px)",
            WebkitBackdropFilter: "blur(20px)",
            border: "1px solid rgba(255,255,255,0.35)",
          }}
        >
          <p className="text-white/60 text-xs uppercase tracking-widest mb-1">Total Balance</p>
          <p className="text-white text-4xl font-bold tracking-tight mb-6">€4,820.00</p>

          {/* Exchange */}
          <div
            className="rounded-2xl p-4 mb-5"
            style={{
              background: "rgba(255,255,255,0.1)",
              border: "1px solid rgba(255,255,255,0.2)",
            }}
          >
            <p className="text-white/50 text-xs uppercase tracking-widest mb-3">Exchange</p>
            <div className="flex items-center gap-3">

              {/* From */}
              <div className="flex-1">
                <div className="flex items-center gap-2 mb-1">
                  <span className="text-lg">{flags[from]}</span>
                  <select
                    value={from}
                    onChange={(e) => setFrom(e.target.value)}
                    className="bg-transparent text-white text-sm font-medium outline-none cursor-pointer"
                  >
                    {currencies.map((c) => (
                      <option key={c} value={c} className="text-black">{c}</option>
                    ))}
                  </select>
                </div>
                <input
                  type="number"
                  value={amount}
                  onChange={(e) => setAmount(e.target.value)}
                  className="w-full bg-transparent text-white text-xl font-semibold outline-none placeholder-white/40"
                  placeholder="0"
                />
              </div>

              {/* Swap Button */}
              <button
                onClick={() => { setFrom(to); setTo(from); }}
                className="flex items-center justify-center w-9 h-9 rounded-full transition-all active:scale-90"
                style={{ background: "rgba(255,255,255,0.2)", border: "1px solid rgba(255,255,255,0.3)" }}
              >
                <svg className="w-4 h-4 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                  <path strokeLinecap="round" strokeLinejoin="round" d="M7 16V4m0 0L3 8m4-4l4 4M17 8v12m0 0l4-4m-4 4l-4-4" />
                </svg>
              </button>

              {/* To */}
              <div className="flex-1 text-right">
                <div className="flex items-center gap-2 justify-end mb-1">
                  <select
                    value={to}
                    onChange={(e) => setTo(e.target.value)}
                    className="bg-transparent text-white text-sm font-medium outline-none cursor-pointer"
                  >
                    {currencies.map((c) => (
                      <option key={c} value={c} className="text-black">{c}</option>
                    ))}
                  </select>
                  <span className="text-lg">{flags[to]}</span>
                </div>
                <p className="text-white text-xl font-semibold">
                  {symbols[to]}{converted}
                </p>
              </div>
            </div>
          </div>

          {/* Action Buttons */}
          <div className="flex gap-3">
            <button className="flex-1 flex items-center justify-center gap-2 bg-white text-red-600 font-semibold rounded-2xl py-3 text-sm transition-all active:scale-95 hover:bg-white/90">
              <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" />
              </svg>
              Send
            </button>
            <button
              className="flex-1 flex items-center justify-center gap-2 font-medium rounded-2xl py-3 text-sm text-white transition-all active:scale-95"
              style={{ background: "rgba(255,255,255,0.15)", border: "1px solid rgba(255,255,255,0.3)" }}
            >
              <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M12 4v16m8-8H4" />
              </svg>
              Add Money
            </button>
          </div>
        </div>

        {/* Transactions Card */}
        <div
          className="rounded-3xl p-5"
          style={{
            background: "rgba(255,255,255,0.12)",
            backdropFilter: "blur(16px)",
            WebkitBackdropFilter: "blur(16px)",
            border: "1px solid rgba(255,255,255,0.22)",
          }}
        >
          <p className="text-white/60 text-xs uppercase tracking-widest mb-4">Recent</p>
          <div className="flex flex-col gap-4">
            {transactions.map((t, i) => (
              <div key={i} className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <div
                    className="w-9 h-9 rounded-full flex items-center justify-center text-base"
                    style={{ background: "rgba(255,255,255,0.15)" }}
                  >
                    {t.icon}
                  </div>
                  <div>
                    <p className="text-white text-sm font-medium">{t.name}</p>
                    <p className="text-white/50 text-xs">{t.date}</p>
                  </div>
                </div>
                <span className={`text-sm font-semibold ${t.positive ? "text-green-300" : "text-white"}`}>
                  {t.amount}
                </span>
              </div>
            ))}
          </div>
        </div>

        {/* Bottom Nav */}
        <div className="flex justify-center gap-6 px-4">
          {["Home", "Exchange", "Cards", "Profile"].map((label, i) => (
            <button key={label} className="flex flex-col items-center gap-1">
              <div
                className={`w-8 h-8 rounded-full flex items-center justify-center transition-all ${i === 0 ? "bg-white" : ""}`}
                style={i !== 0 ? { background: "rgba(255,255,255,0.15)" } : {}}
              >
                <div className={`w-3 h-3 rounded-full ${i === 0 ? "bg-red-500" : "bg-white/50"}`} />
              </div>
              <span className={`text-xs ${i === 0 ? "text-white font-medium" : "text-white/50"}`}>{label}</span>
            </button>
          ))}
        </div>

      </div>
    </div>
  );
}
